// Router: extract callback_data and user info into flat fields
const update = $input.first().json;
let route = '';
let chat_id = '';
let first_name = '';
let telegram_id = '';
let message_id = '';

if (update.callback_query) {
  route = (update.callback_query.data || '').toLowerCase().trim();
  chat_id = update.callback_query.message.chat.id;
  first_name = update.callback_query.from.first_name || '';
  telegram_id = String(update.callback_query.from.id);
  message_id = update.callback_query.message.message_id;
} else if (update.message) {
  const text = (update.message.text || '').trim().toLowerCase();
  if (text === '/start') route = 'start';
  else if (text === '/menu') route = 'menu';
  else route = 'unknown';
  chat_id = update.message.chat.id;
  first_name = update.message.from.first_name || '';
  telegram_id = String(update.message.from.id);
  message_id = update.message.message_id;
}

return [{
  json: {
    _route: route,
    chat_id: chat_id,
    first_name: first_name,
    telegram_id: telegram_id,
    message_id: message_id
  }
}];

